mapper.select:
SELECT cert_serial, issuer_id, subject_id, is_current, not_after, first_activated_at, created_at, updated_at
FROM pki_app.${tableName}
WHERE cert_serial = #{certSerial}
  AND issuer_id = #{issuerId}

mapper.delete:
DELETE FROM pki_app.${tableName}
WHERE cert_serial = #{certSerial}
  AND issuer_id = #{issuerId}
